                                    <span className="bg-white px-2 py-0.5 rounded text-xs border">{stageClients.length}</span>
                                </div>
                                <div className="flex-1 p-3 overflow-y-auto space-y-3 pb-20">
                                    {stageClients.map(client => (
                                        <div 
                                            key={client.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, client)}
                                            onClick={() => onSelectClient(client)}
                                            className="bg-white p-4 rounded-lg shadow-sm border border-gray-100 cursor-grab hover:shadow-md transition whitespace-normal"
                                        >
                                            <div className="flex justify-between items-start mb-1">
                                                <p className="font-bold text-brand-900 text-sm">{client.name}</p>
                                                <p className="text-[9px] text-gray-400 font-mono">{formatDate(client.createdAt)}</p>
                                            </div>
                                            <p className="text-xs text-gray-500 mb-2">{client.prgd}</p>
                                            <div className="text-[9px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded inline-block">
                                                {calculateDaysElapsed(client.createdAt)} dias decorridos
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )
                    })}
                </div>
             </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types';
import { generateTemplateContent } from '../services/templateService';
import { Copy, Phone, Zap, Calendar, Edit2, Save, MessageSquare, Clock, CheckCircle } from 'lucide-react';
import { STAGES } from '../constants';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [content, setContent] = useState<GeneratedContent | null>(null);
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    const currentValues = { ...client.stageData, ...fieldValues };
    const generated = generateTemplateContent(stage, client, currentValues);
    setContent(generated);
    if (!isEditing) {
        setEditableBody(generated.body);
    }
  }, [stage, client, fieldValues, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return null;
    return new Date(isoString).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
  };

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("Este cliente não tem telefone cadastrado!");
      return;
    }

    // 1. Abrir WhatsApp
    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    const url = `https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`;
    window.open(url, '_blank');

    // 2. Atualizar o status do cliente no sistema (avançar funil)
    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(field => {
      const val = fieldValues[field] || client.stageData?.[field];
      return val && val.trim().length > 0;
  });

  if (!content) return null;

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      {/* Header */}
      <div className="bg-brand-900 p-6 shrink-0 flex items-center justify-between text-white relative">
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-1">
             <span className="bg-gold-500 text-brand-900 text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-wider shadow-sm">
               Etapa {stage.stepNumber}
             </span>
             <h2 className="text-xl font-bold text-white tracking-tight">{stage.title}</h2>
          </div>
          <p className="text-brand-200 text-xs mt-1">{stage.description}</p>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden bg-gray-50/50">

        {/* Left Column: Data & History */}
        <div className="lg:w-[340px] p-6 overflow-y-auto border-r border-gray-200 flex flex-col gap-6 bg-white shrink-0">

          {/* Client Info Card */}
          <div className="bg-white border border-gray-100 rounded-xl p-4 shadow-sm ring-1 ring-gray-100">
             <div className="flex items-center gap-3 mb-3 border-b border-gray-50 pb-2">
                <div className="bg-brand-50 p-2 rounded-full">
                    <Zap size={16} className="text-gold-500 fill-gold-500" />
                </div>
                <div className="flex-1 min-w-0">
                    <h3 className="text-sm font-bold text-brand-900 leading-tight truncate">{client.name}</h3>
                    <p className="text-[10px] text-gray-500 flex items-center gap-1">
                        <Clock size={10} /> Criado em: {new Date(client.createdAt).toLocaleDateString('pt-BR')}
                    </p>
                </div>
             </div>
             <div className="grid grid-cols-2 gap-2">
                 <div className="bg-gray-50 p-2 rounded border border-gray-100">
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Telefone</p>
                    <p className="text-xs font-mono font-medium text-gray-700">{client.phone}</p>
                 </div>
                 <div className="bg-gray-50 p-2 rounded border border-gray-100">
                    <p className="text-[10px] text-gray-400 font-bold uppercase">PRGD</p>
                    <p className="text-xs font-mono font-medium text-gray-700">{client.prgd}</p>
                 </div>
             </div>
          </div>

          {/* Histórico da Jornada */}
          <div className="bg-gray-50/50 rounded-xl border border-gray-200 p-4">
            <h4 className="text-[10px] font-bold text-brand-800 uppercase tracking-widest mb-4 flex items-center gap-2">
                <Clock size={14} /> Histórico de Execução
            </h4>
            <div className="space-y-4 relative">
                {/* Linha vertical decorativa */}
                <div className="absolute left-2.5 top-2 bottom-2 w-0.5 bg-gray-200"></div>

                {STAGES.map((s, idx) => {
                    const completedDate = client.stageHistory[s.id];
                    const isCurrent = s.id === client.currentStageId;

                    if (!completedDate && !isCurrent) return null;

                    return (
                        <div key={s.id} className="relative pl-8">
                            <div className={`absolute left-0 top-1 w-5 h-5 rounded-full border-2 flex items-center justify-center z-10 transition-colors
                                ${completedDate ? 'bg-green-500 border-green-500 text-white' : 'bg-white border-brand-300'}`}>
                                {completedDate ? <CheckCircle size={12} /> : <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-pulse" />}
                            </div>
                            <div className="flex flex-col">
                                <span className={`text-[11px] font-bold leading-none ${completedDate ? 'text-brand-900' : 'text-brand-400'}`}>
                                    {s.title}
                                </span>
                                <span className="text-[9px] text-gray-400 mt-1 font-mono">
                                    {completedDate ? formatDate(completedDate) : 'Em andamento...'}
                                </span>
                            </div>
                        </div>
                    );
                })}
            </div>
          </div>

          {/* Required Fields Inputs */}
          {requiredFields.length > 0 && (
            <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4">
                <label className="block text-xs font-bold text-yellow-800 mb-3 uppercase tracking-wider flex items-center gap-2">
                    <Calendar size={14} /> Dados Necessários
                </label>
                <div className="space-y-3">
                    {requiredFields.map(variable => {
                        const currentValue = fieldValues[variable] || client.stageData?.[variable] || '';
                        return (
                            <div key={variable}>
                                <label className="block text-xs font-medium text-yellow-900 mb-1 capitalize">
                                    {variable}
                                </label>
                                <input 
                                    type="text"
                                    value={currentValue}
                                    onChange={(e) => handleFieldChange(variable, e.target.value)}
                                    className="w-full px-3 py-2 border border-yellow-300 rounded-lg focus:ring-2 focus:ring-yellow-500/50 outline-none text-sm bg-white"
                                    placeholder={`Digite ${variable}...`}
                                />
                            </div>
                        );
                    })}
                </div>
            </div>
          )}

           <div className="mt-auto pt-4">
             <button 
               onClick={() => setIsEditing(!isEditing)}
               className={`w-full py-2 px-4 rounded-lg text-sm font-bold flex items-center justify-center gap-2 transition border ${isEditing ? 'bg-brand-50 text-brand-700 border-brand-200' : 'bg-white text-gray-500 border-gray-200 hover:border-gray-300'}`}
             >
                {isEditing ? <Save size={16} /> : <Edit2 size={16} />}
                {isEditing ? 'Parar Edição' : 'Editar Texto Manualmente'}
             </button>
           </div>
        </div>

        {/* Right Column: Preview & Action */}
        <div className="flex-1 p-6 h-full overflow-hidden flex flex-col bg-gray-50/30">
            <div className="flex-1 min-h-0 flex flex-col"> 
                <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col transition hover:shadow-md relative h-full">
                    <div className="bg-gray-50 px-4 py-3 border-b border-gray-100 flex justify-between items-center shrink-0">
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                            <MessageSquare size={14} /> Pré-visualização da Mensagem
                        </span>
                        <div className="flex gap-2">
                            <button onClick={() => copyToClipboard(editableBody)} className="text-gray-400 hover:text-brand-600 transition p-1" title="Copiar Texto">
                                <Copy size={16} />
                            </button>
                        </div>
                    </div>

                    <div className="p-6 relative flex-1 overflow-y-auto bg-white">
                        {isEditing ? (
                            <textarea 
                                value={editableBody}
                                onChange={(e) => setEditableBody(e.target.value)}
                                className="w-full h-full resize-none outline-none text-gray-800 text-sm leading-7 font-sans bg-transparent border-none p-0"
                            />
                        ) : (
                            <div className="whitespace-pre-line text-gray-800 text-sm leading-7 font-sans select-all pb-10">
                                {editableBody}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="pt-4 shrink-0 mt-4 border-t border-gray-200">
                <button 
                  onClick={handleWhatsAppClick}
                  disabled={!areAllFieldsFilled}
                  className={`w-full py-4 rounded-xl font-bold text-white transition shadow-lg flex items-center justify-center gap-3 text-lg transform active:scale-[0.99] hover:scale-[1.01]
                    ${!areAllFieldsFilled
                        ? 'bg-gray-300 cursor-not-allowed text-gray-500' 
                        : 'bg-[#25D366] hover:bg-[#20bd5a] shadow-green-200 hover:shadow-green-300'}`}
                >
                  <Phone size={24} />
                  {!areAllFieldsFilled ? 'Preencha os dados para enviar' : 'Enviar no WhatsApp'}
                </button>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Timeline } from './components/Timeline';
import { ContentGenerator } from './components/ContentGenerator';
import { ClientList } from './components/ClientList';
import { STAGES } from './constants';
import { Client, Stage } from './types';
import { ArrowLeft, Settings, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'list' | 'detail'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);

  // State for list of clients
  const [clients, setClients] = useState<Client[]>([]);

  const handleCreateClient = (newClient: Client) => {
    // A data de criação já vem preenchida do ClientList, mas garantimos aqui se necessário
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    const stageToSet = client.currentStageId || STAGES[0].id;
    setCurrentStageId(stageToSet);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  // Função central para atualizar etapa e dados vinculados (vinda do Drag & Drop ou Botão)
  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();

    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        const updatedStageData = stageData ? { ...c.stageData, ...stageData } : c.stageData;

        // Atualiza o histórico com a data atual para a nova etapa
        const updatedHistory = { 
          ...c.stageHistory, 
          [newStageId]: now 
        };

        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: updatedStageData,
          stageHistory: updatedHistory
        };
      }
      return c;
    }));

    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const handleStageSelect = (stage: Stage) => {
    setCurrentStageId(stage.id);
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans text-slate-800">

      {/* Header */}
      <header className="bg-brand-900 border-b border-gold-600/30 shrink-0 z-50 shadow-lg relative overflow-hidden h-16 sm:h-20">
        <div className="absolute top-0 right-0 w-64 h-full bg-gradient-to-l from-brand-800 to-transparent opacity-50"></div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-full flex items-center justify-between relative z-10">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button 
                onClick={() => setView('list')}
                className="p-2 hover:bg-white/10 rounded-full text-gold-100 transition"
              >
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex items-center gap-3">
              <div className="bg-white/10 p-2 rounded-lg border border-white/20 hidden sm:block">
                 <Zap className="text-gold-500 fill-gold-500" size={24} />
              </div>
              <div className="flex flex-col justify-center">
                <h1 className="text-2xl sm:text-3xl font-black text-white tracking-tighter leading-none uppercase">
                  LOOP <span className="text-gold-500">ENERGIA</span>
                </h1>
                <p className="text-[10px] text-brand-300 uppercase tracking-widest font-medium pl-0.5">
                  Gestão de Experiência do Cliente
                </p>
              </div>
            </div>
          </div>

          <nav className="flex items-center gap-6">
             {selectedClient && view === 'detail' && (
               <div className="hidden md:block text-right border-r border-brand-700 pr-6">
                 <p className="text-[10px] text-gold-400 font-bold uppercase tracking-wider mb-0.5">Cliente Ativo</p>
                 <p className="text-sm font-bold text-white flex items-center gap-2 justify-end">
                   {selectedClient.name}
                   <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></span>
                 </p>
               </div>
             )}
            <a href="#" className="text-brand-100 hover:text-white font-medium text-sm flex items-center gap-2 transition hover:bg-white/5 px-3 py-2 rounded-lg">
              <Settings size={18} /> <span className="hidden sm:inline">Configurações</span>
            </a>
          </nav>
        </div>
      </header>

      {/* Main Container */}
      <main className="flex-1 flex flex-col overflow-hidden relative w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">

        {view === 'list' ? (
            <div className="flex-1 min-h-0 flex flex-col relative">
                <ClientList 
                  clients={clients} 
                  onSelectClient={handleSelectClient} 
                  onCreateClient={handleCreateClient}
                  onUpdateClientStage={handleUpdateClientStage}
                />
            </div>
          ) : (
            <div className="flex flex-col h-full gap-4">
              <div className="shrink-0 w-full">
                <Timeline 
                  currentStageId={currentStageId} 
                  onSelectStage={handleStageSelect} 
                />
              </div>

              <div className="flex-1 min-h-0 pb-2">
                 {selectedClient && (
                   <ContentGenerator 
                     stage={currentStage}
                     client={selectedClient}
                     onUpdateNotes={handleUpdateNotes}
                     onUpdateClientStage={handleUpdateClientStage}
                   />
                 )}
              </div>
            </div>
          )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Client, Stage } from '../types';
import { Plus, Search, User, Zap, Hash, List, Kanban, Phone as PhoneIcon, X, Flag, Calendar, Clock, Timer } from 'lucide-react';
import { STAGES } from '../constants';
import { generateTemplateContent } from '../services/templateService';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  // Drag and Drop State
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  // Transition Modal State
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  // Form State
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    titularName: '',
    projectName: '',
    additionalNotes: ''
  });

  // Reset form when modal opens/closes
  useEffect(() => {
    if (isCreating) {
        setInitialStageId(STAGES[0].id);
        setInitialStageValues({});
    }
  }, [isCreating]);

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
    });
  };

  const calculateDaysElapsed = (createdAt: string) => {
    const start = new Date(createdAt);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - start.getTime());
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      const url = `https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`;
      window.open(url, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.clientNumber || !formData.prgd || !formData.phone) {
      alert("Por favor, preencha os campos obrigatórios: Nome, Telefone, Nº Cliente e PRGD.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    if (selectedStage?.requiredFields) {
        const missingFields = selectedStage.requiredFields.filter(field => !initialStageValues[field]);
        if (missingFields.length > 0) {
            alert(`Para iniciar na etapa "${selectedStage.title}", preencha: ${missingFields.join(', ')}`);
            return;
        }
    }

    const now = new Date().toISOString();

    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      titularName: formData.titularName,
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: formData.additionalNotes || '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };

    if (selectedStage) {
        openWhatsApp(newClient, selectedStage, initialStageValues);
    }

    setIsCreating(false);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', titularName: '', projectName: '', additionalNotes: '' });
    setInitialStageId(STAGES[0].id);
    setInitialStageValues({});
    onCreateClient(newClient);
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
        setTransitionValues({});
      } else {
        onUpdateClientStage(clientId, stageId);
        // Pequeno delay para garantir que o WhatsApp abra após a animação de drop se houver
        setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client) {
        openWhatsApp(client, transitionTargetStage, transitionValues);
      }
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.clientNumber.includes(searchTerm)
  );

  const renderCreateModal = () => {
    const selectedStageObj = STAGES.find(s => s.id === initialStageId);
    return (
    <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[90vh] border border-gold-200 animate-scale-up">
            <div className="flex items-center justify-between p-6 border-b border-gray-100 shrink-0 bg-gradient-to-r from-brand-50 to-white rounded-t-2xl">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 p-2 rounded-lg text-gold-400 shadow-md">
                      <User size={24} />
                    </div>
                    <div>
                      <h2 className="text-xl font-bold text-brand-900">Novo Cliente LOOP ENERGIA</h2>
                      <p className="text-xs text-brand-500 font-medium">Dados essenciais para a jornada.</p>
                    </div>
                </div>
                <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-red-500 transition">
                    <X size={24} />
                </button>
            </div>

            <div className="overflow-y-auto p-8">
                <form id="create-client-form" onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Nome do Cliente <span className="text-red-500">*</span></label>
                            <input 
                                required
                                type="text" 
                                className="w-full p-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none transition font-medium text-brand-900"
                                placeholder="Nome completo"
                                value={formData.name}
                                onChange={e => setFormData({...formData, name: e.target.value})}
                            />
                        </div>
                        <div>
                             <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Telefone (WhatsApp) <span className="text-red-500">*</span></label>
                             <div className="relative">
                                <PhoneIcon className="absolute left-3 top-3.5 text-gray-400" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none transition font-mono text-sm"
                                    placeholder="(99) 99999-9999"
                                    value={formData.phone}
                                    onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})}
                                />
                             </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">PRGD <span className="text-red-500">*</span></label>
                            <div className="relative">
                                <Zap className="absolute left-3 top-3.5 text-gold-500" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none uppercase font-mono text-sm font-bold text-brand-800"
                                    placeholder="Ex: GD-2024-999"
                                    value={formData.prgd}
                                    onChange={e => setFormData({...formData, prgd: e.target.value})}
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Número do Cliente <span className="text-red-500">*</span></label>
                            <div className="relative">
                                <Hash className="absolute left-3 top-3.5 text-gray-400" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none font-mono text-sm"
                                    placeholder="ID ou CRM"
                                    value={formData.clientNumber}
                                    onChange={e => setFormData({...formData, clientNumber: e.target.value})}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="bg-brand-50/50 p-4 rounded-xl border border-brand-100">
                        <label className="block text-xs font-bold uppercase text-brand-600 mb-2 flex items-center gap-2">
                             <Flag size={14} className="text-brand-500" /> Etapa Inicial
                        </label>
                        <select
                            value={initialStageId}
                            onChange={(e) => setInitialStageId(e.target.value)}
                            className="w-full p-3 border border-gray-200 bg-white rounded-lg focus:ring-2 focus:ring-brand-500/20 outline-none text-sm font-medium text-brand-900"
                        >
                            {STAGES.map(stage => (
                                <option key={stage.id} value={stage.id}>
                                    {stage.stepNumber} - {stage.title}
                                </option>
                            ))}
                        </select>
                        {selectedStageObj?.requiredFields && selectedStageObj.requiredFields.length > 0 && (
                            <div className="mt-4 bg-yellow-50 border border-yellow-200 rounded-lg p-4 animate-fade-in">
                                <label className="block text-xs font-bold text-yellow-800 mb-3 uppercase flex items-center gap-2">
                                    <Calendar size={14} /> Dados Necessários para {selectedStageObj.title}
                                </label>
                                <div className="space-y-3">
                                    {selectedStageObj.requiredFields.map(field => (
                                        <div key={field}>
                                            <label className="block text-xs font-medium text-yellow-900 mb-1 capitalize">
                                                {field} <span className="text-red-500">*</span>
                                            </label>
                                            <input 
                                                required
                                                type="text"
                                                className="w-full px-3 py-2 border border-yellow-300 rounded focus:ring-2 focus:ring-yellow-500/50 outline-none text-sm bg-white"
                                                placeholder={`Informe: ${field}`}
                                                value={initialStageValues[field] || ''}
                                                onChange={(e) => setInitialStageValues({...initialStageValues, [field]: e.target.value})}
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                     <div>
                        <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Observações</label>
                        <textarea 
                            className="w-full p-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none h-20 resize-none transition text-sm"
                            placeholder="Detalhes extras..."
                            value={formData.additionalNotes}
                            onChange={e => setFormData({...formData, additionalNotes: e.target.value})}
                        />
                    </div>
                </form>
            </div>

            <div className="p-6 border-t border-gray-100 bg-gray-50 rounded-b-2xl shrink-0 flex justify-end gap-3">
                 <button onClick={() => setIsCreating(false)} className="px-6 py-3 rounded-xl font-bold text-gray-500 hover:bg-gray-200 transition">Cancelar</button>
                 <button 
                    form="create-client-form"
                    type="submit" 
                    className="bg-brand-800 text-white font-bold py-3 px-8 rounded-xl shadow-lg hover:bg-brand-900 transition flex items-center gap-2"
                >
                    <Plus size={20} className="text-gold-400" />
                    Cadastrar e Enviar
                </button>
            </div>
        </div>
    </div>
    );
  };

  const renderTransitionModal = () => {
    if (!transitionTargetStage || !transitionClientId) return null;
    const client = clients.find(c => c.id === transitionClientId);

    return (
      <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md border-2 border-gold-400 overflow-hidden animate-scale-up">
          <div className="bg-brand-900 p-6">
               <h3 className="text-white font-bold text-lg mb-1">Preencher Dados: {transitionTargetStage.title}</h3>
               <p className="text-brand-200 text-xs">Cliente: {client?.name}</p>
          </div>

          <form onSubmit={handleTransitionSubmit} className="p-6 space-y-4">
             {transitionTargetStage.requiredFields?.map(field => (
               <div key={field}>
                 <label className="block text-xs font-bold text-brand-800 uppercase mb-1 capitalize">{field}</label>
                 <input 
                   required
                   autoFocus
                   type="text"
                   className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500 outline-none"
                   placeholder={`Digite o valor para [${field}]...`}
                   value={transitionValues[field] || ''}
                   onChange={e => setTransitionValues({...transitionValues, [field]: e.target.value})}
                 />
               </div>
             ))}

             <div className="flex justify-end gap-2 pt-4">
                <button type="button" onClick={() => setTransitionTargetStage(null)} className="px-4 py-2 text-gray-500 hover:bg-gray-100 rounded-lg font-bold text-sm">Cancelar</button>
                <button type="submit" className="px-6 py-2 bg-gold-500 text-brand-900 rounded-lg font-bold text-sm shadow-md">Salvar e Enviar</button>
             </div>
          </form>
        </div>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {isCreating && renderCreateModal()}
      {transitionTargetStage && renderTransitionModal()}

      <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4 shrink-0">
        <div>
            <h2 className="text-2xl font-bold text-brand-900">Carteira de Clientes</h2>
            <p className="text-gray-500 text-sm">Total: {clients.length}</p>
        </div>
        <div className="flex items-center gap-3">
             <div className="bg-gray-100 p-1 rounded-lg flex border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`p-2 rounded-md ${viewMode === 'list' ? 'bg-white shadow text-brand-900' : 'text-gray-400'}`}><List size={20}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2 rounded-md ${viewMode === 'pipeline' ? 'bg-white shadow text-brand-900' : 'text-gray-400'}`}><Kanban size={20}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-900 text-white px-5 py-2.5 rounded-lg font-bold text-sm shadow-lg hover:bg-brand-800 flex items-center gap-2">
                <Plus size={18} className="text-gold-400" /> Novo Cliente
             </button>
        </div>
      </div>

      <div className="px-6 py-4 bg-gray-50/50 border-b border-gray-100 shrink-0">
         <div className="relative">
            <Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
            <input 
                type="text" 
                placeholder="Buscar cliente..." 
                className="w-full pl-10 p-3 rounded-xl border border-gray-200 focus:border-brand-500 outline-none"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
            />
         </div>
      </div>

      <div className="flex-1 overflow-hidden relative">
        {viewMode === 'list' && (
             <div className="h-full overflow-y-auto p-6 pb-20 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 content-start">
                {filteredClients.map(client => {
                    const daysElapsed = calculateDaysElapsed(client.createdAt);
                    const isWarning = daysElapsed > 90;
                    const isCritical = daysElapsed > 120;

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-200 rounded-xl p-5 cursor-pointer hover:border-gold-400 hover:shadow-lg transition group h-fit flex flex-col gap-3">
                            <div className="flex justify-between items-start">
                                <h3 className="font-bold text-brand-900 text-lg truncate pr-2">{client.name}</h3>
                                <span className="bg-brand-50 text-brand-800 text-[10px] font-bold px-2 py-1 rounded shrink-0">#{client.clientNumber}</span>
                            </div>

                            <div className="text-sm text-gray-500 flex flex-wrap items-center gap-x-4 gap-y-1">
                                 <div className="flex items-center gap-1.5"><Zap size={14} className="text-gold-500" /> {client.prgd}</div>
                                 <div className="flex items-center gap-1.5 text-xs"><Clock size={12} /> {formatDate(client.createdAt)}</div>
                            </div>

                            {/* Seção de Prazos */}
                            <div className="bg-gray-50 rounded-lg p-3 border border-gray-100 flex flex-col gap-1.5">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2 text-[10px] font-bold text-gray-400 uppercase tracking-wider">
                                        <Timer size={12} /> Prazo: 120 dias
                                    </div>
                                    <div className={`text-[10px] font-black uppercase tracking-widest ${isCritical ? 'text-red-500' : isWarning ? 'text-orange-500' : 'text-green-600'}`}>
                                        {isCritical ? 'Excedido' : 'No Prazo'}
                                    </div>
                                </div>
                                <div className="text-xs font-bold text-brand-800">
                                    Decorridos: <span className={isCritical ? 'text-red-600' : isWarning ? 'text-orange-600' : 'text-brand-900'}>
                                        {daysElapsed} dias
                                    </span>
                                </div>
                                <div className="w-full h-1 bg-gray-200 rounded-full overflow-hidden mt-1">
                                    <div 
                                        className={`h-full transition-all duration-500 ${isCritical ? 'bg-red-500' : isWarning ? 'bg-orange-500' : 'bg-green-500'}`}
                                        style={{ width: `${Math.min((daysElapsed / 120) * 100, 100)}%` }}
                                    ></div>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 text-xs font-bold text-gray-400 uppercase tracking-wider mt-1">
                                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                                {STAGES.find(s => s.id === client.currentStageId)?.title}
                            </div>
                        </div>
                    );
                })}
             </div>
        )}

        {viewMode === 'pipeline' && (
             <div className="h-full overflow-x-auto p-6 pb-20 whitespace-nowrap">
                <div className="inline-flex gap-4 h-full">
                    {STAGES.map(stage => {
                        const stageClients = clients.filter(c => (c.currentStageId || '1') === stage.id);
                        return (
                            <div 
                                key={stage.id}
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, stage.id)}
                                className={`w-80 bg-gray-50 rounded-xl border border-gray-200 flex flex-col h-full ${draggedClientId ? 'border-dashed border-brand-300' : ''}`}
                            >
                                <div className="p-4 font-bold text-brand-900 border-b border-gray-200 flex justify-between shrink-0">
                                    {stage.title}
                                    <span className="bg-white px-2 py-0.5 rounded text-xs border">{stageClients.length}</span>
                                </div>
                                <div className="flex-1 p-3 overflow-y-auto space-y-3 pb-20">
                                    {stageClients.map(client => {
                                        const days = calculateDaysElapsed(client.createdAt);
                                        const isUrgent = days > 120;
                                        const isWarning = days > 90;

                                        return (
                                            <div 
                                                key={client.id}
                                                draggable
                                                onDragStart={(e) => handleDragStart(e, client)}
                                                onClick={() => onSelectClient(client)}
                                                className="bg-white p-4 rounded-lg shadow-sm border border-gray-100 cursor-grab hover:shadow-md transition whitespace-normal flex flex-col gap-2"
                                            >
                                                <div className="flex justify-between items-start">
                                                    <p className="font-bold text-brand-900 text-sm leading-tight pr-2">{client.name}</p>
                                                    <p className="text-[8px] text-gray-400 font-mono shrink-0">{formatDate(client.createdAt)}</p>
                                                </div>
                                                <p className="text-[10px] text-gray-500">{client.prgd}</p>

                                                {/* Status Resumido Solicitado */}
                                                <div className="flex items-center justify-between mt-1 pt-2 border-t border-gray-50">
                                                    <div className="flex items-center gap-1.5">
                                                        <div className={`w-2 h-2 rounded-full shadow-sm ${isUrgent ? 'bg-red-500 animate-pulse' : isWarning ? 'bg-yellow-400' : 'bg-green-500'}`}></div>
                                                        <span className={`text-[10px] font-black uppercase tracking-wider ${isUrgent ? 'text-red-600' : isWarning ? 'text-yellow-600' : 'text-green-600'}`}>
                                                            {isUrgent ? 'Urgente' : isWarning ? 'Atenção' : 'No Prazo'}
                                                        </span>
                                                    </div>
                                                    <span className="text-[9px] font-bold text-gray-400">{days}d</span>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )
                    })}
                </div>
             </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Client, Stage } from '../types';
import { Plus, Search, User, Zap, Hash, List, Kanban, Phone as PhoneIcon, X, Flag, Calendar, Clock, Timer } from 'lucide-react';
import { STAGES } from '../constants';
import { generateTemplateContent } from '../services/templateService';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  // Drag and Drop State
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  // Transition Modal State
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  // Form State
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    titularName: '',
    projectName: '',
    additionalNotes: ''
  });

  // Reset form when modal opens/closes
  useEffect(() => {
    if (isCreating) {
        setInitialStageId(STAGES[0].id);
        setInitialStageValues({});
    }
  }, [isCreating]);

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
    });
  };

  const calculateDaysElapsed = (createdAt: string) => {
    const start = new Date(createdAt);
    const now = new Date();
    const diffTime = Math.abs(now.getTime() - start.getTime());
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      const url = `https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`;
      window.open(url, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.clientNumber || !formData.prgd || !formData.phone) {
      alert("Por favor, preencha os campos obrigatórios: Nome, Telefone, Nº Cliente e PRGD.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    if (selectedStage?.requiredFields) {
        const missingFields = selectedStage.requiredFields.filter(field => !initialStageValues[field]);
        if (missingFields.length > 0) {
            alert(`Para iniciar na etapa "${selectedStage.title}", preencha: ${missingFields.join(', ')}`);
            return;
        }
    }

    const now = new Date().toISOString();

    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      titularName: formData.titularName,
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: formData.additionalNotes || '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };

    if (selectedStage) {
        openWhatsApp(newClient, selectedStage, initialStageValues);
    }

    setIsCreating(false);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', titularName: '', projectName: '', additionalNotes: '' });
    setInitialStageId(STAGES[0].id);
    setInitialStageValues({});
    onCreateClient(newClient);
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
        setTransitionValues({});
      } else {
        onUpdateClientStage(clientId, stageId);
        // Pequeno delay para garantir que o WhatsApp abra após a animação de drop se houver
        setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client) {
        openWhatsApp(client, transitionTargetStage, transitionValues);
      }
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.clientNumber.includes(searchTerm)
  );

  const renderCreateModal = () => {
    const selectedStageObj = STAGES.find(s => s.id === initialStageId);
    return (
    <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[90vh] border border-gold-200 animate-scale-up">
            <div className="flex items-center justify-between p-6 border-b border-gray-100 shrink-0 bg-gradient-to-r from-brand-50 to-white rounded-t-2xl">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 p-2 rounded-lg text-gold-400 shadow-md">
                      <User size={24} />
                    </div>
                    <div>
                      <h2 className="text-xl font-bold text-brand-900">Novo Cliente LOOP ENERGIA</h2>
                      <p className="text-xs text-brand-500 font-medium">Dados essenciais para a jornada.</p>
                    </div>
                </div>
                <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-red-500 transition">
                    <X size={24} />
                </button>
            </div>

            <div className="overflow-y-auto p-8">
                <form id="create-client-form" onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Nome do Cliente <span className="text-red-500">*</span></label>
                            <input 
                                required
                                type="text" 
                                className="w-full p-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none transition font-medium text-brand-900"
                                placeholder="Nome completo"
                                value={formData.name}
                                onChange={e => setFormData({...formData, name: e.target.value})}
                            />
                        </div>
                        <div>
                             <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Telefone (WhatsApp) <span className="text-red-500">*</span></label>
                             <div className="relative">
                                <PhoneIcon className="absolute left-3 top-3.5 text-gray-400" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none transition font-mono text-sm"
                                    placeholder="(99) 99999-9999"
                                    value={formData.phone}
                                    onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})}
                                />
                             </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">PRGD <span className="text-red-500">*</span></label>
                            <div className="relative">
                                <Zap className="absolute left-3 top-3.5 text-gold-500" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none uppercase font-mono text-sm font-bold text-brand-800"
                                    placeholder="Ex: GD-2024-999"
                                    value={formData.prgd}
                                    onChange={e => setFormData({...formData, prgd: e.target.value})}
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Número do Cliente <span className="text-red-500">*</span></label>
                            <div className="relative">
                                <Hash className="absolute left-3 top-3.5 text-gray-400" size={16} />
                                <input 
                                    required
                                    type="text" 
                                    className="w-full pl-10 pr-4 py-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none font-mono text-sm"
                                    placeholder="ID ou CRM"
                                    value={formData.clientNumber}
                                    onChange={e => setFormData({...formData, clientNumber: e.target.value})}
                                />
                            </div>
                        </div>
                    </div>

                    <div className="bg-brand-50/50 p-4 rounded-xl border border-brand-100">
                        <label className="block text-xs font-bold uppercase text-brand-600 mb-2 flex items-center gap-2">
                             <Flag size={14} className="text-brand-500" /> Etapa Inicial
                        </label>
                        <select
                            value={initialStageId}
                            onChange={(e) => setInitialStageId(e.target.value)}
                            className="w-full p-3 border border-gray-200 bg-white rounded-lg focus:ring-2 focus:ring-brand-500/20 outline-none text-sm font-medium text-brand-900"
                        >
                            {STAGES.map(stage => (
                                <option key={stage.id} value={stage.id}>
                                    {stage.stepNumber} - {stage.title}
                                </option>
                            ))}
                        </select>
                        {selectedStageObj?.requiredFields && selectedStageObj.requiredFields.length > 0 && (
                            <div className="mt-4 bg-yellow-50 border border-yellow-200 rounded-lg p-4 animate-fade-in">
                                <label className="block text-xs font-bold text-yellow-800 mb-3 uppercase flex items-center gap-2">
                                    <Calendar size={14} /> Dados Necessários para {selectedStageObj.title}
                                </label>
                                <div className="space-y-3">
                                    {selectedStageObj.requiredFields.map(field => (
                                        <div key={field}>
                                            <label className="block text-xs font-medium text-yellow-900 mb-1 capitalize">
                                                {field} <span className="text-red-500">*</span>
                                            </label>
                                            <input 
                                                required
                                                type="text"
                                                className="w-full px-3 py-2 border border-yellow-300 rounded focus:ring-2 focus:ring-yellow-500/50 outline-none text-sm bg-white"
                                                placeholder={`Informe: ${field}`}
                                                value={initialStageValues[field] || ''}
                                                onChange={(e) => setInitialStageValues({...initialStageValues, [field]: e.target.value})}
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                     <div>
                        <label className="block text-xs font-bold uppercase text-brand-600 mb-2">Observações</label>
                        <textarea 
                            className="w-full p-3 border border-gray-200 bg-gray-50 rounded-xl focus:bg-white focus:ring-2 focus:ring-brand-500/20 outline-none h-20 resize-none transition text-sm"
                            placeholder="Detalhes extras..."
                            value={formData.additionalNotes}
                            onChange={e => setFormData({...formData, additionalNotes: e.target.value})}
                        />
                    </div>
                </form>
            </div>

            <div className="p-6 border-t border-gray-100 bg-gray-50 rounded-b-2xl shrink-0 flex justify-end gap-3">
                 <button onClick={() => setIsCreating(false)} className="px-6 py-3 rounded-xl font-bold text-gray-500 hover:bg-gray-200 transition">Cancelar</button>
                 <button 
                    form="create-client-form"
                    type="submit" 
                    className="bg-brand-800 text-white font-bold py-3 px-8 rounded-xl shadow-lg hover:bg-brand-900 transition flex items-center gap-2"
                >
                    <Plus size={20} className="text-gold-400" />
                    Cadastrar e Enviar
                </button>
            </div>
        </div>
    </div>
    );
  };

  const renderTransitionModal = () => {
    if (!transitionTargetStage || !transitionClientId) return null;
    const client = clients.find(c => c.id === transitionClientId);

    return (
      <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md border-2 border-gold-400 overflow-hidden animate-scale-up">
          <div className="bg-brand-900 p-6">
               <h3 className="text-white font-bold text-lg mb-1">Preencher Dados: {transitionTargetStage.title}</h3>
               <p className="text-brand-200 text-xs">Cliente: {client?.name}</p>
          </div>

          <form onSubmit={handleTransitionSubmit} className="p-6 space-y-4">
             {transitionTargetStage.requiredFields?.map(field => (
               <div key={field}>
                 <label className="block text-xs font-bold text-brand-800 uppercase mb-1 capitalize">{field}</label>
                 <input 
                   required
                   autoFocus
                   type="text"
                   className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-gold-500 outline-none"
                   placeholder={`Digite o valor para [${field}]...`}
                   value={transitionValues[field] || ''}
                   onChange={e => setTransitionValues({...transitionValues, [field]: e.target.value})}
                 />
               </div>
             ))}

             <div className="flex justify-end gap-2 pt-4">
                <button type="button" onClick={() => setTransitionTargetStage(null)} className="px-4 py-2 text-gray-500 hover:bg-gray-100 rounded-lg font-bold text-sm">Cancelar</button>
                <button type="submit" className="px-6 py-2 bg-gold-500 text-brand-900 rounded-lg font-bold text-sm shadow-md">Salvar e Enviar</button>
             </div>
          </form>
        </div>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {isCreating && renderCreateModal()}
      {transitionTargetStage && renderTransitionModal()}

      <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4 shrink-0">
        <div>
            <h2 className="text-2xl font-bold text-brand-900">Carteira de Clientes</h2>
            <p className="text-gray-500 text-sm">Total: {clients.length}</p>
        </div>
        <div className="flex items-center gap-3">
             <div className="bg-gray-100 p-1 rounded-lg flex border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`p-2 rounded-md ${viewMode === 'list' ? 'bg-white shadow text-brand-900' : 'text-gray-400'}`}><List size={20}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2 rounded-md ${viewMode === 'pipeline' ? 'bg-white shadow text-brand-900' : 'text-gray-400'}`}><Kanban size={20}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-900 text-white px-5 py-2.5 rounded-lg font-bold text-sm shadow-lg hover:bg-brand-800 flex items-center gap-2">
                <Plus size={18} className="text-gold-400" /> Novo Cliente
             </button>
        </div>
      </div>

      <div className="px-6 py-4 bg-gray-50/50 border-b border-gray-100 shrink-0">
         <div className="relative">
            <Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
            <input 
                type="text" 
                placeholder="Buscar cliente..." 
                className="w-full pl-10 p-3 rounded-xl border border-gray-200 focus:border-brand-500 outline-none"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
            />
         </div>
      </div>

      <div className="flex-1 overflow-hidden relative">
        {viewMode === 'list' && (
             <div className="h-full overflow-y-auto p-6 pb-20 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 content-start">
                {filteredClients.map(client => {
                    const daysElapsed = calculateDaysElapsed(client.createdAt);
                    const isWarning = daysElapsed > 90;
                    const isCritical = daysElapsed > 120;

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-200 rounded-xl p-5 cursor-pointer hover:border-gold-400 hover:shadow-lg transition group h-fit flex flex-col gap-3">
                            <div className="flex justify-between items-start">
                                <h3 className="font-bold text-brand-900 text-lg truncate pr-2">{client.name}</h3>
                                <span className="bg-brand-50 text-brand-800 text-[10px] font-bold px-2 py-1 rounded shrink-0">#{client.clientNumber}</span>
                            </div>

                            <div className="text-sm text-gray-500 flex flex-wrap items-center gap-x-4 gap-y-1">
                                 <div className="flex items-center gap-1.5"><Zap size={14} className="text-gold-500" /> {client.prgd}</div>
                                 <div className="flex items-center gap-1.5 text-xs"><Clock size={12} /> {formatDate(client.createdAt)}</div>
                            </div>

                            {/* Seção de Prazos */}
                            <div className="bg-gray-50 rounded-lg p-3 border border-gray-100 flex flex-col gap-1.5">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2 text-[10px] font-bold text-gray-400 uppercase tracking-wider">
                                        <Timer size={12} /> Prazo: 120 dias
                                    </div>
                                    <div className={`text-[10px] font-black uppercase tracking-widest ${isCritical ? 'text-red-500' : isWarning ? 'text-orange-500' : 'text-green-600'}`}>
                                        {isCritical ? 'Excedido' : 'No Prazo'}
                                    </div>
                                </div>
                                <div className="text-xs font-bold text-brand-800">
                                    Decorridos: <span className={isCritical ? 'text-red-600' : isWarning ? 'text-orange-600' : 'text-brand-900'}>
                                        {daysElapsed} dias
                                    </span>
                                </div>
                                <div className="w-full h-1 bg-gray-200 rounded-full overflow-hidden mt-1">
                                    <div 
                                        className={`h-full transition-all duration-500 ${isCritical ? 'bg-red-500' : isWarning ? 'bg-orange-500' : 'bg-green-500'}`}
                                        style={{ width: `${Math.min((daysElapsed / 120) * 100, 100)}%` }}
                                    ></div>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 text-xs font-bold text-gray-400 uppercase tracking-wider mt-1">
                                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                                {STAGES.find(s => s.id === client.currentStageId)?.title}
                            </div>
                        </div>
                    );
                })}
             </div>
        )}

        {viewMode === 'pipeline' && (
             <div className="h-full overflow-x-auto p-6 pb-20 whitespace-nowrap">
                <div className="inline-flex gap-4 h-full">
                    {STAGES.map(stage => {
                        const stageClients = clients.filter(c => (c.currentStageId || '1') === stage.id);
                        return (
                            <div 
                                key={stage.id}
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, stage.id)}
                                className={`w-80 bg-gray-50 rounded-xl border border-gray-200 flex flex-col h-full ${draggedClientId ? 'border-dashed border-brand-300' : ''}`}
                            >
                                <div className="p-4 font-bold text-brand-900 border-b border-gray-200 flex justify-between shrink-0">
                                    {stage.title}
                                    <span className="bg-white px-2 py-0.5 rounded text-xs border">{stageClients.length}</span>
                                </div>
                                <div className="flex-1 p-3 overflow-y-auto space-y-3 pb-20">
                                    {stageClients.map(client => {
                                        const days = calculateDaysElapsed(client.createdAt);
                                        const isUrgent = days > 120;
                                        const isWarning = days > 90;

                                        return (
                                            <div 
                                                key={client.id}
                                                draggable
                                                onDragStart={(e) => handleDragStart(e, client)}
                                                onClick={() => onSelectClient(client)}
                                                className="bg-white p-4 rounded-lg shadow-sm border border-gray-100 cursor-grab hover:shadow-md transition whitespace-normal flex flex-col gap-2"
                                            >
                                                <div className="flex justify-between items-start">
                                                    <p className="font-bold text-brand-900 text-sm leading-tight pr-2">{client.name}</p>
                                                    <p className="text-[8px] text-gray-400 font-mono shrink-0">{formatDate(client.createdAt)}</p>
                                                </div>
                                                <p className="text-[10px] text-gray-500">{client.prgd}</p>

                                                {/* Status Resumido com Contador X/120 dias */}
                                                <div className="flex items-center justify-between mt-1 pt-2 border-t border-gray-50">
                                                    <div className="flex items-center gap-1.5">
                                                        <div className={`w-2 h-2 rounded-full shadow-sm ${isUrgent ? 'bg-red-500 animate-pulse' : isWarning ? 'bg-yellow-400' : 'bg-green-500'}`}></div>
                                                        <span className={`text-[10px] font-black uppercase tracking-wider ${isUrgent ? 'text-red-600' : isWarning ? 'text-yellow-600' : 'text-green-600'}`}>
                                                            {isUrgent ? 'Urgente' : isWarning ? 'Atenção' : 'No Prazo'}
                                                        </span>
                                                    </div>
                                                    <span className={`text-[9px] font-black tracking-tight ${isUrgent ? 'text-red-600' : 'text-gray-400'}`}>
                                                        {days}/120 dias
                                                    </span>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )
                    })}
                </div>
             </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types';
import { generateTemplateContent } from '../services/templateService';
import { Copy, Phone, Zap, Calendar, Edit2, Save, MessageSquare, Clock, CheckCircle, Timer, AlertCircle } from 'lucide-react';
import { STAGES } from '../constants';

interface ContentGeneratorProps {
  stage: Stage;
